void solve() {
    int n, k, q;
    cin >> n >> k >> q;

    struct Query { int c, l, r; };
    vector<Query> queries(q);
    vector<bool> must_ge_k(n + 1, false);
    vector<bool> must_not_be_k(n + 1, false);

    for (int i = 0; i < q; ++i) {
        cin >> queries[i].c >> queries[i].l >> queries[i].r;
        if (queries[i].c == 1) {
            for (int j = queries[i].l; j <= queries[i].r; ++j) must_ge_k[j] = true;
        } else {
            for (int j = queries[i].l; j <= queries[i].r; ++j) must_not_be_k[j] = true;
        }
    }

    vector<int> a(n + 1, -1);
    for (int i = 1; i <= n; ++i) {
        if (must_ge_k[i]) {
            if (must_not_be_k[i]) a[i] = k + 1; 
            else a[i] = k; 
        }
    }

    for (int i = 0; i < q; ++i) {
        if (queries[i].c == 2) {
            int L = queries[i].l, R = queries[i].r;
            for (int v = 0; v < k; ++v) {
                bool found = false;
                for (int j = L; j <= R; ++j) {
                    if (a[j] == v) { found = true; break; }
                }
                if (!found) {
                    for (int j = L; j <= R; ++j) {
                        if (a[j] == -1) {
                            a[j] = v;
                            found = true;
                            break;
                        }
                    }
                }
            }
        }
    }

    for (int i = 1; i <= n; ++i) {
        if (a[i] == -1) {
            if (must_not_be_k[i]) a[i] = 0;
            else a[i] = k + 1;
        }
        cout << a[i] << (i == n ? "" : " ");
    }
    cout << "\n";
}

