        if (c == 1) {
            c1[l]++;
            c1[r + 1]--;
        } else {
            c2[l]++;
            c2[r + 1]--;

            mex.push_back({l, r});
        }
    }


    vector<int> a(n + 1, -1); // -1 = unset
    for (int i = 1; i <= n; i++) {
